package faest

import (
	"bytes"
	"testing"
)

// TestROHashKAT validates the FAEST random oracles against the vectors embedded
// in faest-rs src/random_oracles.rs (H0/H1/H2^{0..3}/H3/H4, SHAKE128 & SHAKE256).
func TestROHashKAT(t *testing.T) {
	cases := []struct {
		name    string
		use256  bool
		sep     byte
		in, out string
	}{
		{"h0_128", false, sepH0, "e1523a8980c16283cbc85e71703a04d1", "cbbf57a90b618753c6970423e70c5f230607fe367199e52a875d506974b32bda4bca01fc296018d6f1146d59474b7943"},
		{"h0_256", true, sepH0, "d7fcc8ac7923ae971b08c7a2fc1f0a81", "aa9d0ab0359d51d9ea4303e849f5a3b763b0b7e5f4f47006a86b9376a05b82da651eb25aa7d93a12445869949cd4428138a21899c059c20b4d356e38ae834840fe47002f91f3442f5a329a262e5b50ab97fed4578c00ed7f3be7fbb910de8f0c"},
		{"h1_128", false, sepH1, "d2331c8bd91b1e0156590944472d2dd3", "93e35fee7382c6ce22e934494abf2c901c58b51aa3402424d27da58e5c4fddd9"},
		{"h1_256", true, sepH1, "d5b25115aa4c5b3c1a962095cddb31ba", "897e86b9697f4c2d6b267671f24319570127162b3bd5f56d3049c45c02420bd056be22f4a056d4a51fb1e8255343137ee45f12c734774a4cbce735d0b6746d01"},
		{"h2a_128", false, sepH2a, "462c150b96cb0ec4071a054674cd352ed4da35338bea59ad660608c12f86e8eb594775a731df928c819b2d2ae2d8959c", "8af990d03ecdc10ebf71169f2e2d1da7cb661a44c938c7cd011a2a213fb6bd52"},
		{"h2a_256", true, sepH2a, "c084c7fdf5981076ac49fa76b1b62815b9ceb2c6d8546acf2675797edbc7c257e5caea3699e1e798bf7dc81c1d891029e628e77713a1d3e9a9ad826cff77212bb27b5af489368f32f57ae9d10cfc2dec7b970e063f85dd466639fc80074c194b", "a2e031d8c4e6c64bff74a737e33b82dff206ce8259dad20bda68bbe1b059c26982a9fea884b00d0e34e9aaa1cc20856d70fa60c83a2587cc6894f0189450eca5"},
		{"h2b_128", false, sepH2b, "2a52ca6f92b7b18e4c5801da83d06d441a8489ecb9b9e0b0d2e11579771074f1ab33814657c2b4395343f1429ae5f287709940c32d7472498d3e71c7a65b6d52ff543cf8e53341e55906ea2ccd96082f542fe8b231464d83b886a2f16da8cee0", "f1d0110efc8e483231d2b282731fee4e36a769bd5b4143dcce730dfca4386325c91a82719d1b2cb011b893aba9448b1dd79148bafdcfc69d2694338bd22ad116c4e246994b2dde0b5f5724f8796bf1508b038f3767c47151"},
		{"h2b_256", true, sepH2b, "", ""},
		{"h2c_128", false, sepH2c, "61cfa65d016da45b95ba0697f0a1b736099a50b6f219ababdc453c2e2aaed1e102dda972bebc85ed38e89b687c74505e15833a7312079f77b177061e0c9b546a10d33eb09abc418a737987404284ea0d080b7940d913913b1d59f3661ee3be75e5fb28ec8f5944267447c3a43df52ba3474272187b217dfd68da7244d02906d0", "241e1e8924a969c6a505012532e1ceebc656618b8d417da209c220fc6c75acaf066671e3d9d3bcedef459e23441564a24eb739a6e049da6b"},
		{"h2c_256", true, sepH2c, "", "0f03c0e761793ef25c6b33be8d42477080ac0d5055c670d6b78e818510b6a200b56c02673f8ab7296295a1b7c0d0296e411647f770bc32a7cebb7f6fad2c92074c32f86557525a319f32f638586a6c948ca8f6a02f9e8ed51b171c228d498f8f46abb024c5b5a6b8"},
		{"h2d_128", false, sepH2d, "10f0ca30be9c04a87db4d9e8abaca2a39c66e3f877455150c7b7c339066cf7f9087df295b20c14b0507b07c9ba32b9c1e0d39567c3b1de56a01d1eb839c4fa16ef16c87289c7dd2800621f3d4c4a3a5422e1c19eb6eca3b8c89d42930f670938eb5d6aa94464e450b7717ca0", "37fd54b13b2be1afe131420e0c07d8ad"},
		{"h2d_256", true, sepH2d, "", "7638466eb5adf5f2ed556709a7a27c22cbe692618c47439f629a75cc3d07e218"},
		{"h3_128", false, sepH3, "56b7fcbb3fa12bc267ec1d429af82ddff09474b70657cf61cb68ec7013f052007fb9ebd724d1c6c9886a8eed45cd667eb59ba4ac91b98978f7ab541330e63d47", "fbf3bec09d9968174c859247be3f60b9971ea82932eaae362eb6e97db6bd5d3a"},
		{"h3_256", true, sepH3, "6f35d966a9792324c7fb72c89a11780267f6b13cca501154c1b7376f2f833253d6fc0528dc104a1121caf3d2e6401b0c0f492163e99eef40e72c181cc8651040ccdcb6b448aab4e64082e52f75f6ed10966a21561c5e642a1b5568c02cc6de59095ca454678c4c7d44364146a1a04d912df91ed2b5bd9e8a3a695c448dfead5d", "73e9b5903313072143ecb76352690e3314a7f8ca8485767bae11dc244d2d7d6b842ea9efcd6560c31c0f100599b70409"},
		{"h4_128", false, sepH4, "51a092ffdc6ab1004dc0e4a1147f476a", "e44e9db8aa34fec31b39e1ae22297570"},
		{"h4_256", true, sepH4, "b2e747985d6e184049c1c3ad4aa05e8b", "6882f53cab688eb612a6a894e912614d"},
	}
	for _, c := range cases {
		want := mustHex(t, c.out)
		h := newHasher(c.use256, c.sep)
		h.Update(mustHex(t, c.in))
		got := make([]byte, len(want))
		h.Finish().Read(got)
		if !bytes.Equal(got, want) {
			t.Fatalf("%s: mismatch\n got  %x\n want %x", c.name, got, want)
		}
	}
}
